// src/pages/LoginPage.js
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useSensor } from '../hooks/useSensor';
import FingerprintAuth from '../components/auth/FingerprintAuth';
import './LoginPage.css';

const LoginPage = () => {
    const navigate = useNavigate();
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [useFingerprint, setUseFingerprint] = useState(false);
    const [localError, setLocalError] = useState('');
    const [showFingerprintModal, setShowFingerprintModal] = useState(false);
    
    const { login, loading, error } = useAuth();
    const { status: sensorStatus, connect, disconnect, isSupported } = useSensor();

    // Only enable fingerprint option if sensor is connected
    useEffect(() => {
        if (!sensorStatus.connected) {
            setUseFingerprint(false);
        }
    }, [sensorStatus.connected]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLocalError('');

        if (!username) {
            setLocalError('Username is required');
            return;
        }

        if (!useFingerprint && !password) {
            setLocalError('Password is required');
            return;
        }

        if (useFingerprint) {
            // Show fingerprint modal instead of submitting directly
            setShowFingerprintModal(true);
        } else {
            const result = await login(username, password, false);
            if (!result.success) {
                setLocalError(result.error);
            }
        }
    };

    const handleFingerprintSuccess = async (result) => {
        setShowFingerprintModal(false);
        const loginResult = await login(username, null, true);
        if (!loginResult.success) {
            setLocalError(loginResult.error);
        }
    };

    const handleFingerprintError = (error) => {
        setShowFingerprintModal(false);
        setLocalError(error.message || 'Fingerprint authentication failed');
    };

    const handleConnectSensor = async () => {
        const result = await connect();
        if (!result.success) {
            setLocalError(result.error);
        }
    };

    const handleDisconnectSensor = () => {
        disconnect();
    };

    return (
        <div className="login-page">
            <div className="login-container">
                <h2>Login to E-Health System</h2>
                
                {/* Sensor Connection Status */}
                <div className="sensor-status-section">
                    {!isSupported ? (
                        <div className="sensor-warning">
                            ⚠️ Web Bluetooth not supported. Please use Chrome or Edge browser.
                        </div>
                    ) : !sensorStatus.connected ? (
                        <button 
                            type="button"
                            className="btn-connect"
                            onClick={handleConnectSensor}
                            disabled={loading}
                        >
                            🔵 Connect Fingerprint Sensor
                        </button>
                    ) : (
                        <div className="sensor-badge">
                            <span className="sensor-dot"></span>
                            <span className="sensor-name">{sensorStatus.port}</span>
                            <button 
                                type="button"
                                className="sensor-disconnect"
                                onClick={handleDisconnectSensor}
                            >
                                Disconnect
                            </button>
                        </div>
                    )}
                </div>

                {(localError || error) && (
                    <div className="error-message">
                        {localError || error}
                    </div>
                )}

                <form onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label htmlFor="username">Username</label>
                        <input
                            type="text"
                            id="username"
                            value={username}
                            onChange={(e) => setUsername(e.target.value)}
                            disabled={loading}
                            placeholder="Enter your username"
                        />
                    </div>

                    {!useFingerprint && (
                        <div className="form-group">
                            <label htmlFor="password">Password</label>
                            <input
                                type="password"
                                id="password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                disabled={loading}
                                placeholder="Enter your password"
                            />
                        </div>
                    )}

                    {sensorStatus.connected && (
                        <div className="form-group">
                            <label className="checkbox-label">
                                <input
                                    type="checkbox"
                                    checked={useFingerprint}
                                    onChange={(e) => setUseFingerprint(e.target.checked)}
                                />
                                Use Fingerprint Authentication
                            </label>
                        </div>
                    )}

                    <button 
                        type="submit" 
                        className="btn btn-primary btn-block"
                        disabled={loading || (!useFingerprint && !password) || !username}
                    >
                        {loading ? 'Processing...' : 'Login'}
                    </button>
                </form>

                <div className="login-footer">
                    <p>Don't have an account? <a href="/register">Register here</a></p>
                    <p><a href="/">Back to Home</a></p>
                </div>
            </div>

            {/* Fingerprint Authentication Modal */}
            {showFingerprintModal && (
                <div className="modal-overlay" onClick={() => setShowFingerprintModal(false)}>
                    <div className="modal-content" onClick={e => e.stopPropagation()}>
                        <button className="modal-close" onClick={() => setShowFingerprintModal(false)}>×</button>
                        <FingerprintAuth 
                            onSuccess={handleFingerprintSuccess}
                            onError={handleFingerprintError}
                        />
                    </div>
                </div>
            )}
        </div>
    );
};

export default LoginPage;
